/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Handles template rendering, recipient resolution, and email delivery.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationPayload, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Email template with subject and body formatting.
 */
interface EmailTemplate {
  subject: (payload: NotificationPayload) => string;
  body: (payload: NotificationPayload) => string;
}

/**
 * Built-in templates keyed by notification type.
 */
const DEFAULT_TEMPLATES: Record<NotificationType, EmailTemplate> = {
  'order-confirmation': {
    subject: (p) => `Order Confirmation: ${p.subject}`,
    body: (p) =>
      `Dear Customer,\n\nThank you for your order.\n\n${p.body}\n\nWe will notify you when your order ships.\n\nBest regards,\nTaskFlow Pro`,
  },
  'order-status-update': {
    subject: (p) => `Order Status Update: ${p.subject}`,
    body: (p) =>
      `Dear Customer,\n\n${p.body}\n\nThank you for your patience.\n\nBest regards,\nTaskFlow Pro`,
  },
  welcome: {
    subject: () => 'Welcome to TaskFlow Pro!',
    body: (p) =>
      `Hello ${p.recipient},\n\nWelcome to TaskFlow Pro! We're glad to have you on board.\n\n${p.body}\n\nBest regards,\nTaskFlow Pro`,
  },
  'account-update': {
    subject: () => 'Your Account Has Been Updated',
    body: (p) =>
      `Dear Customer,\n\nYour account has been updated.\n\n${p.body}\n\nIf you did not make this change, please contact support.\n\nBest regards,\nTaskFlow Pro`,
  },
  'system-alert': {
    subject: (p) => `[ALERT] ${p.subject}`,
    body: (p) =>
      `System Alert\n\n${p.body}\n\nThis is an automated notification from TaskFlow Pro.`,
  },
};

/**
 * Represents a rendered email ready for delivery.
 */
export interface RenderedEmail {
  to: string;
  subject: string;
  body: string;
  type: NotificationType;
  metadata?: Record<string, unknown>;
}

/**
 * Delivery function signature. Can be replaced for testing or to swap providers.
 */
export type EmailDeliveryFn = (email: RenderedEmail) => Promise<{ success: boolean; error?: string }>;

/**
 * Default delivery function that logs the email (for dev/test).
 */
const logDelivery =
  (logger: Logger): EmailDeliveryFn =>
  async (email) => {
    logger.info(`Delivering email to ${email.to}: [${email.subject}]`);
    return { success: true };
  };

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private templates: Record<NotificationType, EmailTemplate>;
  private deliverFn: EmailDeliveryFn;

  constructor(options?: {
    templates?: Partial<Record<NotificationType, EmailTemplate>>;
    deliverFn?: EmailDeliveryFn;
  }) {
    this.templates = { ...DEFAULT_TEMPLATES, ...options?.templates };
    this.deliverFn = options?.deliverFn ?? logDelivery(this.logger);
  }

  /**
   * Resolve the recipient address from the payload.
   * If metadata contains an explicit `emailAddress`, use that;
   * otherwise fall back to the payload's recipient field.
   */
  resolveRecipient(payload: NotificationPayload): string {
    const override = payload.metadata?.['emailAddress'];
    if (typeof override === 'string' && override.length > 0) {
      return override;
    }
    return payload.recipient;
  }

  /**
   * Render the email using the template for the notification type.
   */
  renderEmail(payload: NotificationPayload): RenderedEmail {
    const template = this.templates[payload.type];
    const to = this.resolveRecipient(payload);

    return {
      to,
      subject: template.subject(payload),
      body: template.body(payload),
      type: payload.type,
      metadata: payload.metadata,
    };
  }

  /**
   * Send an email notification.
   * Renders the template, resolves the recipient, and delivers.
   * Never throws — returns a failed result on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const email = this.renderEmail(payload);

      if (!email.to || email.to.trim().length === 0) {
        this.logger.warn('Cannot send email: no recipient');
        return { success: false, channel: 'email', error: 'No recipient address' };
      }

      this.logger.info(`Sending ${payload.type} email to ${email.to}`);
      const result = await this.deliverFn(email);

      if (!result.success) {
        this.logger.error(`Failed to deliver email to ${email.to}: ${result.error}`);
        return { success: false, channel: 'email', error: result.error };
      }

      this.logger.info(`Email delivered to ${email.to}`);
      return { success: true, channel: 'email' };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Email send error: ${message}`);
      return { success: false, channel: 'email', error: message };
    }
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * NOTE: This service currently uses TWO different patterns for receiving
 * notifications, which is inconsistent and should be unified:
 *
 * 1. EventBus subscriptions (event-driven) — used for order:created events
 * 2. CallbackRegistry (direct callbacks) — used for order:status-changed events
 *
 * Both approaches work but the mixed usage makes the codebase harder to
 * maintain. A future refactor should pick ONE approach and use it consistently.
 *
 * Depends on:
 * - EventBus (event system) for receiving some events
 * - CallbackRegistry (direct callbacks) for other events
 * - NotificationAdapter implementations for channel-specific delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter, NotificationResult } from '../adapters/notification.adapter.js';
import type { NotificationPayload, NotificationType } from '../models/notification.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  channel: string;
  status: 'sent' | 'failed';
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters = new Map<string, NotificationAdapter>();

  constructor(private eventBus: EventBus, adapters?: NotificationAdapter[]) {
    if (adapters) {
      for (const adapter of adapters) {
        this.adapters.set(adapter.channel, adapter);
      }
    }
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a specific channel.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      type: 'order-confirmation',
      channel: 'email',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      type: 'order-status-update',
      channel: 'email',
    });
  }

  /**
   * Send a notification, dispatching to the appropriate adapter if available.
   */
  private sendNotification(payload: NotificationPayload): void {
    const adapter = this.adapters.get(payload.channel);

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      channel: payload.channel,
      status: 'sent',
      sentAt: new Date(),
    };

    if (adapter) {
      adapter.send(payload).then((result: NotificationResult) => {
        if (!result.success) {
          notification.status = 'failed';
          this.logger.error(
            `Adapter failed for ${payload.channel}: ${result.error}`,
          );
        }
      });
    }

    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

