import { describe, it, expect, vi, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { RenderedEmail, EmailDeliveryFn } from '../../src/adapters/email.adapter.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body content',
    type: 'order-confirmation',
    channel: 'email',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  describe('channel', () => {
    it('should have channel set to email', () => {
      const adapter = new EmailAdapter();
      expect(adapter.channel).toBe('email');
    });
  });

  describe('resolveRecipient', () => {
    it('should use payload recipient by default', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload();
      expect(adapter.resolveRecipient(payload)).toBe('alice@example.com');
    });

    it('should use emailAddress from metadata when present', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload({
        metadata: { emailAddress: 'override@example.com' },
      });
      expect(adapter.resolveRecipient(payload)).toBe('override@example.com');
    });

    it('should fall back to recipient when metadata emailAddress is empty', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload({
        metadata: { emailAddress: '' },
      });
      expect(adapter.resolveRecipient(payload)).toBe('alice@example.com');
    });
  });

  describe('renderEmail', () => {
    it('should render order-confirmation template', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload({ type: 'order-confirmation' });
      const email = adapter.renderEmail(payload);

      expect(email.to).toBe('alice@example.com');
      expect(email.subject).toContain('Order Confirmation');
      expect(email.body).toContain('Thank you for your order');
      expect(email.body).toContain('Test body content');
      expect(email.body).toContain('TaskFlow Pro');
    });

    it('should render order-status-update template', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload({ type: 'order-status-update' });
      const email = adapter.renderEmail(payload);

      expect(email.subject).toContain('Order Status Update');
      expect(email.body).toContain('Thank you for your patience');
    });

    it('should render welcome template', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload({ type: 'welcome' });
      const email = adapter.renderEmail(payload);

      expect(email.subject).toBe('Welcome to TaskFlow Pro!');
      expect(email.body).toContain('Welcome to TaskFlow Pro');
    });

    it('should render account-update template', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload({ type: 'account-update' });
      const email = adapter.renderEmail(payload);

      expect(email.subject).toBe('Your Account Has Been Updated');
      expect(email.body).toContain('contact support');
    });

    it('should render system-alert template', () => {
      const adapter = new EmailAdapter();
      const payload = makePayload({ type: 'system-alert', subject: 'Disk Full' });
      const email = adapter.renderEmail(payload);

      expect(email.subject).toBe('[ALERT] Disk Full');
      expect(email.body).toContain('System Alert');
    });

    it('should allow custom templates', () => {
      const adapter = new EmailAdapter({
        templates: {
          'order-confirmation': {
            subject: () => 'Custom Subject',
            body: () => 'Custom Body',
          },
        },
      });
      const payload = makePayload({ type: 'order-confirmation' });
      const email = adapter.renderEmail(payload);

      expect(email.subject).toBe('Custom Subject');
      expect(email.body).toBe('Custom Body');
    });
  });

  describe('send', () => {
    it('should deliver email successfully with default delivery', async () => {
      const adapter = new EmailAdapter();
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.error).toBeUndefined();
    });

    it('should use custom delivery function', async () => {
      const deliverFn: EmailDeliveryFn = vi.fn(async () => ({ success: true }));
      const adapter = new EmailAdapter({ deliverFn });

      await adapter.send(makePayload());

      expect(deliverFn).toHaveBeenCalledOnce();
      const call = vi.mocked(deliverFn).mock.calls[0]![0];
      expect(call.to).toBe('alice@example.com');
      expect(call.subject).toContain('Order Confirmation');
    });

    it('should return failure when delivery fails', async () => {
      const deliverFn: EmailDeliveryFn = vi.fn(async () => ({
        success: false,
        error: 'SMTP timeout',
      }));
      const adapter = new EmailAdapter({ deliverFn });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('email');
      expect(result.error).toBe('SMTP timeout');
    });

    it('should return failure when delivery throws', async () => {
      const deliverFn: EmailDeliveryFn = vi.fn(async () => {
        throw new Error('Connection refused');
      });
      const adapter = new EmailAdapter({ deliverFn });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('email');
      expect(result.error).toBe('Connection refused');
    });

    it('should return failure when recipient is empty', async () => {
      const adapter = new EmailAdapter();
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('No recipient');
    });

    it('should resolve recipient from metadata emailAddress', async () => {
      const deliverFn: EmailDeliveryFn = vi.fn(async () => ({ success: true }));
      const adapter = new EmailAdapter({ deliverFn });

      await adapter.send(
        makePayload({ metadata: { emailAddress: 'other@example.com' } }),
      );

      const call = vi.mocked(deliverFn).mock.calls[0]![0];
      expect(call.to).toBe('other@example.com');
    });
  });
});
